import { useState, useEffect } from "react";

const C = {
  bg:       "#080809",
  header:   "#0f0f12",
  main:     "#0b0b0e",
  panel:    "#111115",
  ritual:   "#09090c",
  surface:  "#181820",
  surface2: "#20202a",
  border:   "#30303a",
  border2:  "#44444f",
  borderH:  "#c6a45355",
  perla:    "#e4e4e4",
  perla2:   "#c8c8c4",
  perla3:   "#888880",
  oro:      "#c6a453",
  oro2:     "#e8c97a",
  oro_dim:  "#c6a45322",
  oro_b:    "#c6a45355",
  verde:    "#3a7a56",
  verde2:   "#4f9e72",
  verde_dim:"#3a7a5622",
  danger:   "#9a3030",
  warn:     "#8a6020",
};

const MONTHS = [
  { id:"mar", label:"Marzo", weeks:[
    { id:"Mar 9-16", label:"9–16 Mar", days:["Lun","Mar","Mié","Jue","Vie","Sáb","Dom"] },
    { id:"Mar 17-23", label:"17–23 Mar", days:["Lun","Mar","Mié","Jue","Vie","Sáb","Dom"] },
    { id:"Mar 24-30", label:"24–30 Mar", days:["Lun","Mar","Mié","Jue","Vie","Sáb","Dom"] },
  ]},
  { id:"abr", label:"Abril", weeks:[
    { id:"Abr 7-13",  label:"7–13 Abr",  days:["Lun","Mar","Mié","Jue","Vie","Sáb","Dom"] },
    { id:"Abr 14-20", label:"14–20 Abr", days:["Lun","Mar","Mié","Jue","Vie","Sáb","Dom"] },
    { id:"Abr 21-27", label:"21–27 Abr", days:["Lun","Mar","Mié","Jue","Vie","Sáb","Dom"] },
    { id:"Abr 28-30", label:"28–30 Abr", days:["Lun","Mar","Mié"] },
  ]},
];

const ALL_WEEKS  = MONTHS.flatMap(m => m.weeks);
const DAYS_FULL  = { Lun:"Lunes", Mar:"Martes", Mié:"Miérc.", Jue:"Jueves", Vie:"Viern.", Sáb:"Sábado", Dom:"Domingo" };
const DAYS_ORDER = ["Lun","Mar","Mié","Jue","Vie","Sáb","Dom"];
const USERS      = ["Fede","Zikiel"];
const STATUSES   = ["pendiente","en curso","listo"];

const TODAY_JS  = new Date().getDay();
const TODAY_IDX = TODAY_JS === 0 ? 6 : TODAY_JS - 1;
const TODAY_DAY = DAYS_ORDER[TODAY_IDX];

const AVATAR_FEDE   = "data:image/png;base64,";
const AVATAR_ZIKIEL = "data:image/png;base64,";

let _tid = 400, _sid = 4000;

const SEED = [
  { id:16, title:"Lanzar campaña Marzo",  week:"Mar 9-16", day:"Lun", month:"mar", assignee:"Fede",   status:"pendiente", subtasks:[], decayDays:0 },
  { id:17, title:"Reunión con proveedor", week:"Mar 9-16", day:"Mié", month:"mar", assignee:"Zikiel", status:"pendiente", subtasks:[], decayDays:0 },
];

function load(k,d){ try{const s=localStorage.getItem(k);return s?JSON.parse(s):d;}catch{return d;} }
function save(k,v){ try{localStorage.setItem(k,JSON.stringify(v));}catch{} }

// ─── AVATAR ──────────────────────────────────────────────────────────────────
function Avatar({ user, size=32 }) {
  return (
    <div style={{
      width:size, height:size, borderRadius:"50%", flexShrink:0,
      overflow:"hidden",
      border:"2px solid rgba(228,228,228,0.85)",
      boxShadow:"0 0 0 1px rgba(198,164,83,0.35), 0 2px 8px #00000060",
    }}>
      <img src={user==="Fede"?AVATAR_FEDE:AVATAR_ZIKIEL} alt={user}
        style={{ width:"100%",height:"100%",objectFit:"cover",objectPosition:"center top",display:"block" }}/>
    </div>
  );
}

// ─── STATUS BADGE ─────────────────────────────────────────────────────────────
function StatusBadge({ status, onClick }) {
  const cfg = {
    pendiente:  { bg:"#ffffff0a", border:C.border2, color:C.perla3, label:"PENDIENTE" },
    "en curso": { bg:C.oro_dim,   border:C.oro_b,   color:C.oro,    label:"EN CURSO"  },
    listo:      { bg:C.verde_dim, border:`${C.verde}55`, color:C.verde2, label:"LISTO" },
  }[status];
  return (
    <button onClick={onClick} style={{
      background:cfg.bg, border:`1px solid ${cfg.border}`, color:cfg.color,
      borderRadius:4, padding:"3px 10px", cursor:"pointer",
      fontFamily:"inherit", fontSize:9, letterSpacing:1.5, fontWeight:700, transition:"all 0.15s",
    }}>{cfg.label}</button>
  );
}

// ─── TASK MODAL ───────────────────────────────────────────────────────────────
function TaskModal({ task, onClose, onSave, onDelete }) {
  const [t, setT] = useState({ ...task, subtasks: task.subtasks.map(s => ({...s})) });
  const [newSub, setNewSub] = useState("");
  const done=t.subtasks.filter(s=>s.done).length, total=t.subtasks.length;
  const weekObj = ALL_WEEKS.find(w=>w.id===t.week);
  const weekDays = weekObj?.days || DAYS_ORDER;

  return (
    <div onClick={onClose} style={{ position:"fixed",inset:0,background:"#000000cc",zIndex:999,
      display:"flex",alignItems:"center",justifyContent:"center",padding:20,backdropFilter:"blur(6px)" }}>
      <div onClick={e=>e.stopPropagation()} style={{
        background:C.surface, border:`1px solid ${C.border2}`,
        borderTop:`3px solid ${C.oro}`, borderRadius:8,
        padding:"28px 28px", width:"100%", maxWidth:520, maxHeight:"88vh", overflowY:"auto",
        boxShadow:`0 0 80px #00000090, 0 0 40px ${C.oro}14`,
        fontFamily:"'Cormorant Garamond',Georgia,serif", animation:"modalIn 0.2s ease",
      }}>
        <textarea value={t.title} onChange={e=>setT(p=>({...p,title:e.target.value}))}
          style={{ background:"transparent",border:"none",borderBottom:`1px solid ${C.border2}`,
            outline:"none",color:C.perla,fontSize:22,fontWeight:600,fontFamily:"inherit",
            width:"100%",resize:"none",lineHeight:1.4,marginBottom:24,paddingBottom:10 }}
          rows={2} />

        <div style={{ display:"flex",gap:12,flexWrap:"wrap",marginBottom:22 }}>
          <div>
            <div style={{ color:C.oro,fontSize:8,letterSpacing:2,marginBottom:6 }}>SEMANA</div>
            <select value={t.week} onChange={e=>setT(p=>({...p,week:e.target.value}))}
              style={{ background:C.surface2,border:`1px solid ${C.border}`,color:C.perla,
                borderRadius:4,padding:"6px 10px",fontFamily:"inherit",fontSize:12,cursor:"pointer",outline:"none" }}>
              {ALL_WEEKS.map(w=><option key={w.id} value={w.id}>{w.label}</option>)}
            </select>
          </div>
          <div>
            <div style={{ color:C.oro,fontSize:8,letterSpacing:2,marginBottom:6 }}>DÍA</div>
            <select value={t.day} onChange={e=>setT(p=>({...p,day:e.target.value}))}
              style={{ background:C.surface2,border:`1px solid ${C.border}`,color:C.perla,
                borderRadius:4,padding:"6px 10px",fontFamily:"inherit",fontSize:12,cursor:"pointer",outline:"none" }}>
              {weekDays.map(d=><option key={d}>{d}</option>)}
            </select>
          </div>
          <div>
            <div style={{ color:C.oro,fontSize:8,letterSpacing:2,marginBottom:6 }}>RESPONSABLE</div>
            <select value={t.assignee} onChange={e=>setT(p=>({...p,assignee:e.target.value}))}
              style={{ background:C.surface2,border:`1px solid ${C.border}`,color:C.perla,
                borderRadius:4,padding:"6px 10px",fontFamily:"inherit",fontSize:12,cursor:"pointer",outline:"none" }}>
              {USERS.map(u=><option key={u}>{u}</option>)}
            </select>
          </div>
          <div>
            <div style={{ color:C.oro,fontSize:8,letterSpacing:2,marginBottom:6 }}>ESTADO</div>
            <StatusBadge status={t.status} onClick={()=>{
              const i=STATUSES.indexOf(t.status);
              setT(p=>({...p,status:STATUSES[(i+1)%STATUSES.length]}));
            }}/>
          </div>
        </div>

        {total>0&&<div style={{marginBottom:14}}>
          <div style={{height:3,background:C.border,borderRadius:2,overflow:"hidden"}}>
            <div style={{height:"100%",background:t.status==="listo"?C.verde:C.oro,width:`${(done/total)*100}%`,transition:"width 0.4s",borderRadius:2}}/>
          </div>
          <div style={{fontSize:10,color:C.perla3,marginTop:5}}>{done} de {total} subtareas</div>
        </div>}

        <div style={{marginBottom:22}}>
          <div style={{color:C.oro,fontSize:8,letterSpacing:2,marginBottom:10}}>SUBTAREAS</div>
          {t.subtasks.map(s=>(
            <div key={s.id} style={{display:"flex",alignItems:"center",gap:10,borderBottom:`1px solid ${C.border}22`,padding:"8px 0"}}>
              <input type="checkbox" checked={s.done}
                onChange={()=>setT(p=>({...p,subtasks:p.subtasks.map(x=>x.id===s.id?{...x,done:!x.done}:x)}))}
                style={{accentColor:C.oro,cursor:"pointer",width:15,height:15}}/>
              <span style={{flex:1,color:s.done?C.perla3:C.perla,textDecoration:s.done?"line-through":"none",fontSize:14}}>{s.title}</span>
              <button onClick={()=>setT(p=>({...p,subtasks:p.subtasks.filter(x=>x.id!==s.id)}))}
                style={{background:"none",border:"none",color:C.perla3,cursor:"pointer",fontSize:16,padding:"0 4px"}}>✕</button>
            </div>
          ))}
          <div style={{display:"flex",gap:8,marginTop:12}}>
            <input value={newSub} onChange={e=>setNewSub(e.target.value)}
              onKeyDown={e=>{if(e.key==="Enter"&&newSub.trim()){setT(p=>({...p,subtasks:[...p.subtasks,{id:_sid++,title:newSub.trim(),done:false}]}));setNewSub("");}}}
              placeholder="Nueva subtarea..." style={{flex:1,background:C.surface2,border:`1px solid ${C.border}`,
                color:C.perla,borderRadius:4,padding:"7px 10px",fontFamily:"inherit",fontSize:13,outline:"none"}}/>
            <button onClick={()=>{if(!newSub.trim())return;setT(p=>({...p,subtasks:[...p.subtasks,{id:_sid++,title:newSub.trim(),done:false}]}));setNewSub("");}}
              style={{background:C.oro_dim,border:`1px solid ${C.oro_b}`,color:C.oro,borderRadius:4,padding:"7px 16px",cursor:"pointer",fontFamily:"inherit",fontSize:14}}>+</button>
          </div>
        </div>

        <div style={{display:"flex",justifyContent:"space-between",paddingTop:18,borderTop:`1px solid ${C.border}`}}>
          <button onClick={()=>onDelete(task.id)} style={{background:"none",border:`1px solid ${C.danger}44`,color:"#b05050",borderRadius:4,padding:"9px 18px",cursor:"pointer",fontFamily:"inherit",fontSize:10,letterSpacing:1}}>ELIMINAR</button>
          <button onClick={()=>onSave(t)} style={{background:C.oro_dim,border:`1px solid ${C.oro}`,color:C.oro,borderRadius:4,padding:"9px 32px",cursor:"pointer",fontFamily:"inherit",fontSize:10,letterSpacing:2,fontWeight:700}}>GUARDAR</button>
        </div>
      </div>
    </div>
  );
}

// ─── TASK CARD ────────────────────────────────────────────────────────────────
function TaskCard({ task, onOpen, onQuickDone, compact=false }) {
  const [hover,setHover] = useState(false);
  const done=task.subtasks.filter(s=>s.done).length, total=task.subtasks.length;
  const decay=task.decayDays||0;
  const isListo=task.status==="listo", isEnCurso=task.status==="en curso";
  const isCritical=decay>=3&&!isListo, isWarn=decay>=1&&!isListo;
  const lb=isListo?C.verde:isEnCurso?C.oro:isCritical?C.danger:isWarn?C.warn:C.border;

  return (
    <div style={{display:"flex",gap:7,alignItems:"stretch",animation:"fadeUp 0.2s ease"}}>
      <button onClick={e=>{e.stopPropagation();onQuickDone(task);}} style={{
        flexShrink:0, width:36,
        background:isListo?C.verde_dim:hover?"#ffffff0a":"transparent",
        border:`1px solid ${isListo?C.verde:C.border}`,
        borderRadius:5, cursor:"pointer", color:isListo?C.verde2:C.perla3,
        fontSize:18, display:"flex",alignItems:"center",justifyContent:"center",
        transition:"all 0.2s",
      }}>{isListo?"✓":""}</button>

      <div onClick={()=>onOpen(task)} onMouseEnter={()=>setHover(true)} onMouseLeave={()=>setHover(false)}
        style={{
          flex:1, background:hover?C.surface2:C.surface,
          border:`1px solid ${hover?C.border2:C.border}`,
          borderLeft:`3px solid ${lb}`,
          borderRadius:5, padding:compact?"8px 12px":"11px 14px",
          cursor:"pointer", transition:"all 0.18s",
          boxShadow:hover?"0 2px 20px #00000050":"none",
          position:"relative", overflow:"hidden",
        }}>
        {isCritical&&<div style={{position:"absolute",inset:0,background:"linear-gradient(90deg,transparent,#9a303009,transparent)",animation:"shimmer 2.5s infinite",pointerEvents:"none"}}/>}
        <div style={{
          color:isListo?C.perla3:C.perla, fontSize:compact?12:14, fontWeight:500,
          lineHeight:1.5, textDecoration:isListo?"line-through":"none",
          marginBottom:(total>0||decay>0)?7:0, opacity:isListo?0.5:1,
        }}>{task.title}</div>
        {(total>0||decay>0)&&<div style={{display:"flex",alignItems:"center",gap:8}}>
          <Avatar user={task.assignee} size={18}/>
          {total>0&&<><div style={{flex:1,height:2,background:C.border,borderRadius:1}}>
            <div style={{background:isListo?C.verde:C.oro,height:"100%",borderRadius:1,width:`${(done/total)*100}%`,transition:"width 0.4s"}}/>
          </div><span style={{fontSize:9,color:C.perla3}}>{done}/{total}</span></>}
          {isCritical&&<span style={{fontSize:9,color:"#c05050",letterSpacing:0.5}}>⚠ {decay}d</span>}
          {isWarn&&!isCritical&&<span style={{fontSize:9,color:C.warn}}>{decay}d</span>}
          {isEnCurso&&<div style={{width:5,height:5,borderRadius:"50%",background:C.oro,animation:"pulse 2s infinite"}}/>}
        </div>}
      </div>
    </div>
  );
}

// ─── RIGHT PANEL ──────────────────────────────────────────────────────────────
function RightPanel({ tasks, activeDay, activeWeek, onOpenTask }) {
  const today=tasks.filter(t=>t.day===activeDay&&t.week===activeWeek);
  const todayDone=today.filter(t=>t.status==="listo").length;
  const weekT=tasks.filter(t=>t.week===activeWeek);
  const weekDone=weekT.filter(t=>t.status==="listo").length;
  const fedeT=tasks.filter(t=>t.assignee==="Fede");
  const zikielT=tasks.filter(t=>t.assignee==="Zikiel");
  const urgent=tasks.filter(t=>t.status!=="listo"&&(t.decayDays||0)>=1).sort((a,b)=>(b.decayDays||0)-(a.decayDays||0));
  const upcoming=tasks.filter(t=>t.status==="pendiente"&&!(t.day===activeDay&&t.week===activeWeek)).slice(0,4);
  const currentWeek=ALL_WEEKS.find(w=>w.id===activeWeek);

  function Bar({label,done,total,color}) {
    const pct = total>0 ? (done/total)*100 : 0;
    return (
      <div style={{marginBottom:14}}>
        <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
          <span style={{fontSize:12,color:C.perla2,letterSpacing:0.5}}>{label}</span>
          <span style={{fontSize:12,color:total===0?C.perla3:color,fontWeight:700}}>
            {total===0 ? <span style={{color:C.perla3,fontSize:10}}>sin tareas</span> : <>{done}<span style={{color:C.perla3}}>/{total}</span></>}
          </span>
        </div>
        <div style={{height:4,background:C.border,borderRadius:2,overflow:"hidden"}}>
          {total>0&&<div style={{height:"100%",background:color,borderRadius:2,width:`${pct}%`,
            minWidth:pct>0?4:0,transition:"width 0.5s",
            boxShadow:pct>0?`0 0 6px ${color}88`:""}}/>}
        </div>
        {total>0&&pct===0&&<div style={{fontSize:9,color:C.perla3,marginTop:4,letterSpacing:0.5}}>0 completadas de {total}</div>}
      </div>
    );
  }

  return (
    <div style={{
      flex:"0 0 30%", minWidth:0,
      borderLeft:`2px solid ${C.borderH}`,
      background:C.panel, display:"flex", flexDirection:"column",
      height:"100%", overflowY:"auto",
    }}>
      <div style={{padding:"20px 18px",borderBottom:`1px solid ${C.border2}`}}>
        <div style={{fontSize:9,color:C.oro,letterSpacing:2.5,marginBottom:14}}>PROGRESO</div>
        <Bar label="Hoy" done={todayDone} total={today.length} color={C.oro}/>
        <Bar label={activeWeek} done={weekDone} total={weekT.length} color={C.oro}/>
        <div style={{height:1,background:C.border,margin:"12px 0"}}/>
        {[{user:"Fede",tasks:fedeT},{user:"Zikiel",tasks:zikielT}].map(({user,tasks:ut})=>(
          <div key={user} style={{display:"flex",gap:10,alignItems:"center",marginBottom:12}}>
            <Avatar user={user} size={28}/>
            <div style={{flex:1}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:5}}>
                <span style={{fontSize:13,color:C.perla,letterSpacing:1,fontWeight:600}}>{user}</span>
                <span style={{fontSize:12,color:C.perla,fontWeight:700}}>
                  {ut.filter(t=>t.status==="listo").length}
                  <span style={{color:C.perla3,fontWeight:400}}>/{ut.length}</span>
                </span>
              </div>
              <div style={{height:4,background:C.border,borderRadius:2,overflow:"hidden"}}>
                <div style={{height:"100%",background:user==="Fede"?C.oro:C.perla2,borderRadius:2,
                  width:`${ut.length>0?(ut.filter(t=>t.status==="listo").length/ut.length)*100:0}%`,transition:"width 0.5s"}}/>
              </div>
              {ut.length===0&&<div style={{fontSize:9,color:C.perla3,marginTop:3}}>sin tareas asignadas</div>}
            </div>
          </div>
        ))}
      </div>

      {urgent.length>0&&(
        <div style={{padding:"16px 18px",borderBottom:`1px solid ${C.border2}`}}>
          <div style={{fontSize:8,color:"#c05050",letterSpacing:2.5,marginBottom:12}}>⚠ REQUIEREN ATENCIÓN</div>
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {urgent.slice(0,4).map(t=>(
              <div key={t.id} onClick={()=>onOpenTask(t)}
                style={{padding:"9px 10px",background:C.surface2,cursor:"pointer",transition:"all 0.15s",borderRadius:5,
                  border:`1px solid ${(t.decayDays||0)>=3?"#9a303044":C.warn+"44"}`,
                  borderLeft:`3px solid ${(t.decayDays||0)>=3?C.danger:C.warn}`}}>
                <div style={{fontSize:12,color:C.perla,lineHeight:1.35,marginBottom:5}}>{t.title}</div>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <Avatar user={t.assignee} size={16}/>
                  <span style={{fontSize:9,color:(t.decayDays||0)>=3?"#c05050":C.warn}}>{t.decayDays}d sin actualizar</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      <div style={{padding:"16px 18px",borderBottom:`1px solid ${C.border2}`}}>
        <div style={{fontSize:9,color:C.oro,letterSpacing:2.5,marginBottom:12}}>SEMANA · {activeWeek.toUpperCase()}</div>
        <div style={{display:"flex",gap:4}}>
          {(currentWeek?.days||DAYS_ORDER).map((d)=>{
            const dt=tasks.filter(t=>t.week===activeWeek&&t.day===d);
            const dd=dt.filter(t=>t.status==="listo").length;
            const isActive=d===activeDay, allDone=dt.length>0&&dd===dt.length;
            const hasTasks=dt.length>0;
            return (
              <div key={d} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
                <div style={{fontSize:9,color:isActive?C.oro:C.perla2,fontWeight:isActive?700:400,letterSpacing:0.5}}>
                  {d.slice(0,2).toUpperCase()}
                </div>
                <div style={{
                  width:"100%", height:34, borderRadius:4,
                  background: allDone ? C.verde+"33" : hasTasks ? C.oro+"1a" : C.surface2,
                  border:`1px solid ${isActive?C.oro:allDone?C.verde:hasTasks?C.oro+"44":C.border}`,
                  display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2,
                }}>
                  <div style={{fontSize:11,fontWeight:700,color:allDone?C.verde:hasTasks?C.oro:C.perla3}}>
                    {hasTasks ? dt.length : "—"}
                  </div>
                  {hasTasks&&<div style={{fontSize:7,color:C.perla3}}>{dd}/{dt.length}</div>}
                </div>
              </div>
            );
          })}
        </div>
        <div style={{display:"flex",gap:12,marginTop:10,justifyContent:"center"}}>
          <div style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:8,height:8,borderRadius:2,background:C.oro+"33",border:`1px solid ${C.oro+"44"}`}}/><span style={{fontSize:9,color:C.perla3}}>con tareas</span></div>
          <div style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:8,height:8,borderRadius:2,background:C.verde+"33",border:`1px solid ${C.verde}`}}/><span style={{fontSize:9,color:C.perla3}}>completo</span></div>
        </div>
      </div>

      <div style={{padding:"16px 18px",flex:1}}>
        <div style={{fontSize:9,color:C.oro,letterSpacing:2.5,marginBottom:12}}>PRÓXIMAS TAREAS</div>
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {upcoming.length===0
            ?<div style={{fontSize:11,color:C.perla3,fontStyle:"italic"}}>Sin tareas pendientes</div>
            :upcoming.map(t=>(
              <div key={t.id} onClick={()=>onOpenTask(t)}
                style={{padding:"10px 12px",background:C.surface2,border:`1px solid ${C.border}`,
                  borderLeft:`3px solid ${t.assignee==="Fede"?C.oro:C.perla2}`,
                  borderRadius:5,cursor:"pointer",transition:"all 0.15s"}}>
                <div style={{fontSize:13,color:C.perla,lineHeight:1.3,marginBottom:6,fontWeight:500}}>{t.title}</div>
                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <Avatar user={t.assignee} size={18}/>
                    <span style={{fontSize:11,color:t.assignee==="Fede"?C.oro:C.perla2,fontWeight:600}}>{t.assignee}</span>
                  </div>
                  <span style={{fontSize:10,color:C.perla3}}>{t.day} · {t.week}</span>
                </div>
              </div>
            ))
          }
        </div>
      </div>
    </div>
  );
}

// ─── CELEBRATION ──────────────────────────────────────────────────────────────
function Celebration({ onDone }) {
  useEffect(()=>{const t=setTimeout(onDone,2800);return()=>clearTimeout(t);},[]);
  return (
    <div style={{position:"fixed",inset:0,zIndex:9999,display:"flex",alignItems:"center",justifyContent:"center",
      pointerEvents:"none",background:"#00000035",backdropFilter:"blur(3px)"}}>
      <div style={{background:C.surface,border:`2px solid ${C.oro}`,borderRadius:8,padding:"36px 60px",
        textAlign:"center",animation:"celebrate 2.8s ease forwards",boxShadow:`0 0 120px ${C.oro}35`}}>
        <div style={{fontSize:48,marginBottom:12}}>⚡</div>
        <div style={{fontSize:26,color:C.oro,fontWeight:700,letterSpacing:3,fontFamily:"'Cormorant Garamond',Georgia,serif"}}>DÍA CERRADO</div>
        <div style={{fontSize:13,color:C.perla2,marginTop:8}}>Todas las tareas completadas</div>
      </div>
    </div>
  );
}

// ─── NOTES PANEL ──────────────────────────────────────────────────────────────
function NotesPanel() {
  const NOTES_KEY = "pa_notes_v1";
  const [notes, setNotes] = useState(()=>{
    try{ return JSON.parse(localStorage.getItem(NOTES_KEY))||[]; }catch{ return []; }
  });
  const [text, setText] = useState("");
  const [author, setAuthor] = useState("Fede");

  function addNote() {
    if(!text.trim()) return;
    const note = {
      id: Date.now(),
      text: text.trim(),
      author,
      ts: new Date().toLocaleString("es-AR",{day:"2-digit",month:"2-digit",hour:"2-digit",minute:"2-digit"}),
    };
    const next = [note, ...notes];
    setNotes(next);
    localStorage.setItem(NOTES_KEY, JSON.stringify(next));
    setText("");
  }

  function deleteNote(id) {
    const next = notes.filter(n=>n.id!==id);
    setNotes(next);
    localStorage.setItem(NOTES_KEY, JSON.stringify(next));
  }

  return (
    <div style={{
      flex:"0 0 25%", minWidth:0,
      borderLeft:`2px solid ${C.borderH}`,
      background:"#0d0d11", display:"flex", flexDirection:"column",
      height:"100%",
    }}>
      {/* Header */}
      <div style={{padding:"16px 18px",borderBottom:`1px solid ${C.border2}`,flexShrink:0}}>
        <div style={{fontSize:9,color:C.oro,letterSpacing:2.5,marginBottom:12}}>✦ NOTAS DEL EQUIPO</div>
        {/* Author selector */}
        <div style={{display:"flex",gap:6,marginBottom:10}}>
          {["Fede","Zikiel"].map(u=>(
            <button key={u} onClick={()=>setAuthor(u)} style={{
              flex:1, padding:"6px 0",
              background:author===u?(u==="Fede"?C.oro_dim:"#1a1a2a"):"transparent",
              border:`1px solid ${author===u?(u==="Fede"?C.oro_b:C.perla2+"66"):C.border}`,
              color:author===u?(u==="Fede"?C.oro:C.perla2):C.perla3,
              borderRadius:4, cursor:"pointer", fontFamily:"inherit",
              fontSize:10, letterSpacing:1, transition:"all 0.15s",
            }}>{u.toUpperCase()}</button>
          ))}
        </div>
        {/* Input */}
        <textarea
          value={text}
          onChange={e=>setText(e.target.value)}
          onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();addNote();}}}
          placeholder="Escribí una nota... (Enter para enviar)"
          rows={3}
          style={{
            width:"100%", background:C.surface2,
            border:`1px solid ${C.border}`, borderRadius:4,
            color:C.perla, fontSize:12, fontFamily:"inherit",
            padding:"9px 11px", resize:"none", outline:"none",
            lineHeight:1.5,
          }}
        />
        <button onClick={addNote} style={{
          marginTop:7, width:"100%", padding:"8px 0",
          background:C.oro_dim, border:`1px solid ${C.oro_b}`,
          color:C.oro, borderRadius:4, cursor:"pointer",
          fontFamily:"inherit", fontSize:10, letterSpacing:1.5,
          transition:"all 0.15s",
        }}>AGREGAR NOTA</button>
      </div>

      {/* Notes list */}
      <div style={{flex:1,overflowY:"auto",padding:"14px 18px",display:"flex",flexDirection:"column",gap:10}}>
        {notes.length===0
          ? <div style={{fontSize:12,color:C.perla3,fontStyle:"italic",textAlign:"center",marginTop:24}}>
              Sin notas aún —<br/>sean los primeros en escribir
            </div>
          : notes.map(n=>(
            <div key={n.id} style={{
              padding:"11px 13px",
              background:C.surface2,
              border:`1px solid ${C.border}`,
              borderLeft:`3px solid ${n.author==="Fede"?C.oro:C.perla2}`,
              borderRadius:5,
              position:"relative",
            }}>
              <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:7}}>
                <Avatar user={n.author} size={20}/>
                <span style={{fontSize:11,fontWeight:700,color:n.author==="Fede"?C.oro:C.perla2,letterSpacing:0.5}}>{n.author}</span>
                <span style={{fontSize:9,color:C.perla3,marginLeft:"auto"}}>{n.ts}</span>
              </div>
              <div style={{fontSize:13,color:C.perla,lineHeight:1.55,whiteSpace:"pre-wrap"}}>{n.text}</div>
              <button onClick={()=>deleteNote(n.id)} style={{
                position:"absolute",top:8,right:8,
                background:"none",border:"none",color:C.perla3,
                cursor:"pointer",fontSize:12,lineHeight:1,padding:2,
                opacity:0.5,transition:"opacity 0.15s",
              }}
                onMouseEnter={e=>e.target.style.opacity=1}
                onMouseLeave={e=>e.target.style.opacity=0.5}
              >✕</button>
            </div>
          ))
        }
      </div>
    </div>
  );
}

// ─── MAIN ─────────────────────────────────────────────────────────────────────
export default function App() {
  const [tasks,        setTasks]      = useState(()=>load("pa_v5", SEED));
  const [view,         setView]       = useState("dia");
  const [activeMonth,  setActiveMonth]= useState("mar");
  const [activeWeek,   setActiveWeek] = useState("Mar 9-16");
  const [activeDay,    setActiveDay]  = useState(TODAY_DAY);
  const [showPast,     setShowPast]   = useState(false);
  const [modal,        setModal]      = useState(null);
  const [filterUser,   setFilterUser] = useState("Todos");
  const [celebrate,    setCelebrate]  = useState(false);

  useEffect(()=>{save("pa_v5",tasks);},[tasks]);
  useEffect(()=>{
    const h=e=>{if(e.key==="pa_v5"){try{setTasks(JSON.parse(e.newValue));}catch{}}}
    window.addEventListener("storage",h);
    return()=>window.removeEventListener("storage",h);
  },[]);

  const currentMonth   = MONTHS.find(m=>m.id===activeMonth)||MONTHS[1];
  const activeMonthIdx = MONTHS.findIndex(m=>m.id===activeMonth);
  const pastMonths     = MONTHS.slice(0, activeMonthIdx);
  const currentWeekObj = currentMonth.weeks.find(w=>w.id===activeWeek)||currentMonth.weeks[0];
  const currentDays    = currentWeekObj?.days || DAYS_ORDER;

  function upsertTask(t) {
    const next=tasks.map(x=>x.id===t.id?{...t,decayDays:0}:x);
    setTasks(next); setModal(null);
    const dayTs=next.filter(x=>x.day===activeDay&&x.week===activeWeek);
    if(dayTs.length>0&&dayTs.every(x=>x.status==="listo"))setCelebrate(true);
  }
  function deleteTask(id){setTasks(p=>p.filter(x=>x.id!==id));setModal(null);}
  function addTask(week,day,month){
    const nt={id:_tid++,title:"Nueva tarea",week,day,month:month||activeMonth,assignee:"Fede",status:"pendiente",subtasks:[],decayDays:0};
    setTasks(p=>[...p,nt]); setModal(nt);
  }
  function quickDone(task){
    const updated={...task,status:task.status==="listo"?"pendiente":"listo",decayDays:0};
    const next=tasks.map(x=>x.id===task.id?updated:x);
    setTasks(next);
    const dayTs=next.filter(x=>x.day===activeDay&&x.week===activeWeek);
    if(dayTs.length>0&&dayTs.every(x=>x.status==="listo"))setCelebrate(true);
  }

  const filtered    = tasks.filter(t=>filterUser==="Todos"||t.assignee===filterUser);
  const todayTasks  = tasks.filter(t=>t.day===activeDay&&t.week===activeWeek);
  const todayDone   = todayTasks.filter(t=>t.status==="listo").length;
  const totalDone   = tasks.filter(t=>t.status==="listo").length;
  const pendingToday= todayTasks.filter(t=>t.status!=="listo");
  const pendingN    = todayTasks.length-todayDone;
  const ritualText  = todayTasks.length===0
    ?"Sin tareas para hoy — agregá una"
    :todayDone===todayTasks.length
    ?"✦ Todas las tareas de hoy completadas"
    :`Falta${pendingN===1?"":"n"} ${pendingN} tarea${pendingN===1?"":"s"} para cerrar el día`;

  return (
    <div style={{height:"100vh",width:"100%",background:C.bg,color:C.perla,
      fontFamily:"'Cormorant Garamond','Palatino Linotype',Georgia,serif",display:"flex",flexDirection:"column",overflow:"hidden"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,500;0,600;0,700;1,400&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        html, body, #root{height:100%;background:${C.bg};}
        ::-webkit-scrollbar{width:3px;height:3px;}
        ::-webkit-scrollbar-track{background:${C.bg};}
        ::-webkit-scrollbar-thumb{background:${C.border2};border-radius:2px;}
        input::placeholder,textarea::placeholder{color:${C.perla3};}
        select option{background:${C.surface2};}
        @keyframes shimmer{0%{transform:translateX(-100%)}100%{transform:translateX(200%)}}
        @keyframes fadeUp{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:0.4}}
        @keyframes celebrate{0%{opacity:0;transform:scale(0.85)}15%{opacity:1;transform:scale(1.04)}85%{opacity:1;transform:scale(1)}100%{opacity:0;transform:scale(0.96)}}
        @keyframes modalIn{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}
        .hbtn:hover{background:${C.surface2}!important;border-color:${C.border2}!important;}
        .horo:hover{background:${C.oro_dim}!important;border-color:${C.oro_b}!important;color:${C.oro}!important;}
        .htask:hover{border-color:${C.oro_b}!important;color:${C.perla}!important;}
      `}</style>

      {celebrate&&<Celebration onDone={()=>setCelebrate(false)}/>}

      {/* HEADER */}
      <div style={{borderBottom:`2px solid ${C.borderH}`,padding:"0 24px",display:"flex",alignItems:"stretch",
        background:C.header,height:58,flexShrink:0}}>
        <div style={{display:"flex",alignItems:"center",gap:16,paddingRight:24,borderRight:`1px solid ${C.border}`}}>
          <div>
            <div style={{fontSize:12,fontWeight:700,color:C.oro,letterSpacing:3}}>PALACIO APPLE</div>
            <div style={{fontSize:8,color:C.perla3,letterSpacing:2,marginTop:1}}>COMMAND CENTER · 2026</div>
          </div>
        </div>
        <div style={{display:"flex",alignItems:"stretch",paddingLeft:22}}>
          {[
            {val:`${todayDone}/${todayTasks.length}`,label:"HOY",color:C.oro},
            {val:totalDone,label:"LISTOS",color:C.verde2},
            {val:tasks.length,label:"TOTAL",color:C.perla2},
          ].map((s,i)=>(
            <div key={i} style={{display:"flex",alignItems:"center"}}>
              {i>0&&<div style={{width:1,height:22,background:C.border,margin:"0 20px"}}/>}
              <div style={{textAlign:"center"}}>
                <div style={{fontSize:20,fontWeight:700,color:s.color,lineHeight:1.1}}>{s.val}</div>
                <div style={{fontSize:7,color:C.perla3,letterSpacing:2}}>{s.label}</div>
              </div>
            </div>
          ))}
        </div>
        <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:6}}>
          {["Todos","Fede","Zikiel"].map(u=>(
            <button key={u} onClick={()=>setFilterUser(u)} className="hbtn" style={{
              background:filterUser===u?C.oro_dim:"transparent",
              border:`1px solid ${filterUser===u?C.oro_b:C.border}`,
              color:filterUser===u?C.oro:C.perla3,
              borderRadius:4,padding:"5px 13px",cursor:"pointer",fontFamily:"inherit",fontSize:10,letterSpacing:1,transition:"all 0.15s"
            }}>{u.toUpperCase()}</button>
          ))}
          <div style={{width:1,height:22,background:C.border,margin:"0 6px"}}/>
          {[["dia","DÍA"],["semana","SEMANA"]].map(([v,l])=>(
            <button key={v} onClick={()=>setView(v)} className="hbtn" style={{
              background:view===v?C.oro_dim:"transparent",
              border:`1px solid ${view===v?C.oro_b:C.border}`,
              color:view===v?C.oro:C.perla3,
              borderRadius:4,padding:"5px 14px",cursor:"pointer",fontFamily:"inherit",fontSize:10,letterSpacing:1,transition:"all 0.15s"
            }}>{l}</button>
          ))}
        </div>
      </div>

      {/* BODY */}
      <div style={{display:"flex",flex:1,overflow:"hidden",background:C.main,alignItems:"stretch"}}>
        {/* MAIN */}
        <div style={{flex:"0 0 45%",overflowY:"auto",minWidth:0,background:C.main}}>

          {/* RITUAL BANNER */}
          {view==="dia"&&(
            <div style={{borderBottom:`1px solid ${C.borderH}`,background:C.ritual,padding:"12px 24px"}}>
              <div style={{display:"flex",alignItems:"center",gap:12,flexWrap:"wrap",marginBottom:pendingToday.length>0?10:0}}>
                <div style={{width:7,height:7,borderRadius:"50%",flexShrink:0,
                  background:todayDone===todayTasks.length&&todayTasks.length>0?C.verde:C.oro,
                  animation:"pulse 2s infinite"}}/>
                <span style={{fontSize:10,color:C.oro,letterSpacing:3,fontWeight:700}}>RITUAL DIARIO</span>
                <div style={{width:1,height:14,background:C.border}}/>
                <span style={{fontSize:13,color:C.perla,fontWeight:500}}>{ritualText}</span>
                <div style={{marginLeft:"auto",display:"flex",gap:4}}>
                  {todayTasks.map((_,i)=>(
                    <div key={i} style={{width:8,height:8,borderRadius:2,
                      background:i<todayDone?C.oro:C.border,transition:"background 0.3s"}}/>
                  ))}
                </div>
              </div>
              {pendingToday.length>0&&pendingToday.length<=4&&(
                <div style={{display:"flex",gap:8,paddingLeft:19,flexWrap:"wrap"}}>
                  {pendingToday.map(t=>(
                    <div key={t.id} onClick={()=>setModal(t)} className="htask"
                      style={{
                        fontSize:12, color:C.perla, cursor:"pointer",
                        background:C.surface, border:`1px solid ${C.border2}`,
                        borderLeft:`2px solid ${C.oro_b}`,
                        borderRadius:4, padding:"6px 14px",
                        transition:"all 0.15s",
                        display:"flex", alignItems:"center", gap:8,
                      }}>
                      <Avatar user={t.assignee} size={20}/>
                      <span>{t.title.length>38?t.title.slice(0,38)+"…":t.title}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          <div style={{padding:"22px 26px"}}>
            {/* MONTH TABS */}
            <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:16,
              borderBottom:`1px solid ${C.border}`,paddingBottom:14}}>
              {MONTHS.map((m,i)=>{
                const isActive=m.id===activeMonth;
                const isPast=i<activeMonthIdx;
                return (
                  <button key={m.id}
                    onClick={()=>{setActiveMonth(m.id);setActiveWeek(m.weeks[0].id);setActiveDay(TODAY_DAY);}}
                    style={{
                      background:isActive?C.oro_dim:"transparent",
                      border:`1px solid ${isActive?C.oro_b:C.border}`,
                      color:isActive?C.oro:isPast?"#666660":C.perla3,
                      borderRadius:4,padding:"6px 18px",cursor:"pointer",fontFamily:"inherit",
                      fontSize:11,letterSpacing:2,fontWeight:isActive?700:400,transition:"all 0.15s",
                      opacity:isPast?0.55:1,
                    }}>
                    {m.label.toUpperCase()}
                    {isPast&&<span style={{marginLeft:6,fontSize:9,color:C.verde2}}>✓</span>}
                  </button>
                );
              })}
              <button onClick={()=>setShowPast(p=>!p)} style={{
                marginLeft:"auto",background:"transparent",
                border:`1px solid ${C.border}`,color:C.perla3,
                borderRadius:4,padding:"5px 12px",cursor:"pointer",fontFamily:"inherit",fontSize:9,letterSpacing:1,transition:"all 0.15s"
              }}>{showPast?"OCULTAR HISTORIAL":"VER HISTORIAL"}</button>
            </div>

            {/* WEEK TABS */}
            <div style={{display:"flex",gap:5,marginBottom:22,overflowX:"auto",paddingBottom:4}}>
              {currentMonth.weeks.map(w=>{
                const isActive=w.id===activeWeek;
                const wt=tasks.filter(t=>t.week===w.id);
                const allDone=wt.length>0&&wt.every(t=>t.status==="listo");
                return (
                  <button key={w.id} onClick={()=>{setActiveWeek(w.id);setActiveDay(TODAY_DAY);}}
                    style={{
                      background:isActive?C.oro_dim:"transparent",
                      border:`1px solid ${isActive?C.oro_b:C.border}`,
                      color:isActive?C.oro:C.perla3,
                      borderRadius:4,padding:"6px 16px",cursor:"pointer",fontFamily:"inherit",
                      fontSize:10,letterSpacing:1,fontWeight:isActive?700:400,transition:"all 0.15s",
                      flexShrink:0,whiteSpace:"nowrap",position:"relative",
                    }}>
                    {w.label}
                    {allDone&&<span style={{position:"absolute",top:-5,right:-3,fontSize:9,color:C.verde2}}>✓</span>}
                  </button>
                );
              })}
            </div>

            {/* DAY TABS */}
            {view==="dia"&&(
              <div style={{display:"flex",gap:1,marginBottom:24,borderBottom:`1px solid ${C.border}`,overflowX:"auto"}}>
                {currentDays.map((d)=>{
                  const hasTasks=filtered.filter(t=>t.week===activeWeek&&t.day===d).length>0;
                  const isToday=d===TODAY_DAY, isActive=d===activeDay;
                  return (
                    <button key={d} onClick={()=>setActiveDay(d)} style={{
                      background:"transparent",border:"none",
                      borderBottom:`2px solid ${isActive?C.oro:"transparent"}`,
                      color:isActive?C.oro:hasTasks?C.perla2:C.perla3,
                      padding:"10px 16px",cursor:"pointer",fontFamily:"inherit",
                      fontSize:10,letterSpacing:2,transition:"all 0.15s",position:"relative",
                      fontWeight:isActive?700:400,whiteSpace:"nowrap",flexShrink:0,
                    }}>
                      {(DAYS_FULL[d]||d).toUpperCase()}
                      {isToday&&<div style={{position:"absolute",bottom:-1,left:"50%",transform:"translateX(-50%)",
                        width:4,height:4,borderRadius:"50%",background:C.oro}}/>}
                      {hasTasks&&!isActive&&<div style={{position:"absolute",top:5,right:5,
                        width:3,height:3,borderRadius:"50%",background:C.border2}}/>}
                    </button>
                  );
                })}
              </div>
            )}

            {/* VISTA DÍA */}
            {view==="dia"&&(
              <div style={{maxWidth:720,display:"flex",flexDirection:"column",gap:28}}>
                {USERS.map(user=>{
                  if(filterUser!=="Todos"&&filterUser!==user)return null;
                  const uTasks=filtered.filter(t=>t.week===activeWeek&&t.day===activeDay&&t.assignee===user);
                  const uDone=uTasks.filter(t=>t.status==="listo").length;
                  return (
                    <div key={user}>
                      <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:14,
                        paddingBottom:12,borderBottom:`1px solid ${C.border}`}}>
                        <Avatar user={user} size={36}/>
                        <div>
                          <div style={{fontSize:13,letterSpacing:2,color:C.perla,fontWeight:700}}>{user.toUpperCase()}</div>
                          <div style={{fontSize:10,color:C.perla2,marginTop:2}}>{uTasks.length} tarea{uTasks.length!==1?"s":""} · {uDone} lista{uDone!==1?"s":""}</div>
                        </div>
                        <button onClick={()=>addTask(activeWeek,activeDay,activeMonth)} className="horo" style={{
                          marginLeft:"auto",background:"transparent",border:`1px solid ${C.border}`,color:C.perla3,
                          borderRadius:4,padding:"7px 16px",cursor:"pointer",fontFamily:"inherit",fontSize:10,letterSpacing:1,transition:"all 0.15s"
                        }}>+ AGREGAR</button>
                      </div>
                      <div style={{display:"flex",flexDirection:"column",gap:9}}>
                        {uTasks.length===0
                          ?<div onClick={()=>addTask(activeWeek,activeDay,activeMonth)}
                            style={{border:`1px dashed ${C.border}`,borderRadius:5,padding:22,textAlign:"center",
                              color:C.perla3,fontSize:12,cursor:"pointer",transition:"all 0.15s"}}>
                            Sin tareas — click para agregar
                          </div>
                          :uTasks.map(t=><TaskCard key={t.id} task={t} onOpen={setModal} onQuickDone={quickDone}/>)
                        }
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

            {/* VISTA SEMANA */}
            {view==="semana"&&(
              <div style={{display:"grid",gridTemplateColumns:`repeat(${currentDays.length},1fr)`,gap:12}}>
                {currentDays.map((day)=>{
                  const dt=filtered.filter(t=>t.week===activeWeek&&t.day===day);
                  const dd=dt.filter(t=>t.status==="listo").length;
                  const allDone=dt.length>0&&dd===dt.length;
                  const isToday=day===TODAY_DAY;
                  return (
                    <div key={day}>
                      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",
                        borderTop:`2px solid ${isToday?C.oro:allDone?C.verde:C.border}`,
                        paddingTop:10,marginBottom:8}}>
                        <span style={{fontSize:9,letterSpacing:1.5,color:isToday?C.oro:allDone?C.verde2:C.perla3,fontWeight:600}}>
                          {(DAYS_FULL[day]||day).slice(0,3).toUpperCase()}{isToday?" ·":""}
                        </span>
                        <button onClick={()=>{setActiveDay(day);addTask(activeWeek,day,activeMonth);}}
                          style={{background:"none",border:"none",color:C.perla3,cursor:"pointer",fontSize:18,padding:"0 2px"}}>+</button>
                      </div>
                      <div style={{display:"flex",flexDirection:"column",gap:5}}>
                        {dt.length===0
                          ?<div onClick={()=>{setActiveDay(day);addTask(activeWeek,day,activeMonth);}}
                            style={{border:`1px dashed ${C.border}22`,borderRadius:4,height:36,
                              display:"flex",alignItems:"center",justifyContent:"center",
                              color:"#2a2a2e",fontSize:10,cursor:"pointer"}}>vacío</div>
                          :dt.map(t=><TaskCard key={t.id} task={t} onOpen={setModal} onQuickDone={quickDone} compact/>)
                        }
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

            {/* HISTORIAL */}
            {showPast&&pastMonths.length>0&&(
              <div style={{marginTop:40,borderTop:`1px solid ${C.border}`,paddingTop:28}}>
                <div style={{fontSize:8,color:C.perla3,letterSpacing:3,marginBottom:24}}>HISTORIAL DE MESES ANTERIORES</div>
                {pastMonths.map(m=>(
                  <div key={m.id} style={{marginBottom:32}}>
                    <div style={{fontSize:11,color:C.perla3,letterSpacing:2,marginBottom:14,
                      borderBottom:`1px solid ${C.border}22`,paddingBottom:10,opacity:0.7}}>
                      {m.label.toUpperCase()}
                    </div>
                    {m.weeks.map(w=>{
                      const wt=filtered.filter(t=>t.week===w.id);
                      if(wt.length===0)return null;
                      const wd=wt.filter(t=>t.status==="listo").length;
                      return (
                        <div key={w.id} style={{marginBottom:18}}>
                          <div style={{fontSize:9,color:C.perla3,letterSpacing:1,marginBottom:8,opacity:0.65}}>
                            {w.label} — {wd}/{wt.length} completadas
                          </div>
                          <div style={{display:"flex",flexDirection:"column",gap:5,opacity:0.55}}>
                            {wt.map(t=><TaskCard key={t.id} task={t} onOpen={setModal} onQuickDone={quickDone} compact/>)}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* RIGHT PANEL */}
        <RightPanel tasks={filtered} activeDay={activeDay} activeWeek={activeWeek} onOpenTask={setModal}/>

        {/* NOTES PANEL */}
        <NotesPanel/>
      </div>

      {/* MODAL */}
      {modal&&<TaskModal task={modal} onClose={()=>setModal(null)} onSave={upsertTask} onDelete={deleteTask}/>}
    </div>
  );
}
